import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Plus, Trash2, Edit, ArrowLeft, Package, X, Save, Loader2 } from 'lucide-react';
import CargaMasiva from './CargaMasiva';
import { generarNombreImagen } from '../utils/helpers';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showManual, setShowManual] = useState(false);
  
  const [nuevoProd, setNuevoProd] = useState({
    tipo: '', marca: '', contenido: '', categoria: 'Almacén',
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { cargarOfertas(); }, [localId]);

  const cargarOfertas = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { console.error(e); }
    setLoading(false);
  };

  const handleCargaManual = async (e) => {
    e.preventDefault();
    try {
      const item = {
        ...nuevoProd,
        producto: `${nuevoProd.tipo} ${nuevoProd.marca} ${nuevoProd.contenido}`,
        publicId: generarNombreImagen(nuevoProd.tipo, nuevoProd.marca, nuevoProd.contenido),
        local: localId
      };
      await axios.post(`${API_URL}/api/ofertas`, item);
      setShowManual(false);
      setNuevoProd({ tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: '' });
      cargarOfertas();
    } catch (err) { alert("Error al guardar"); }
  };

  return (
    <div style={containerStyle}>
      <button onClick={() => navigate('/dashboard')} style={btnBack}>
        <ArrowLeft size={18}/> Volver al Dashboard
      </button>

      <div style={headerStyle}>
        <h2>Gestión de Stock</h2>
        <button onClick={() => setShowManual(true)} style={btnPlus}><Plus size={20}/> Carga Manual</button>
      </div>

      <CargaMasiva localId={localId} onComplete={cargarOfertas} />

      {/* MODAL MANUAL */}
      {showManual && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <h3>Nuevo Producto</h3>
            <form onSubmit={handleCargaManual} style={gridForm}>
              <input style={inputS} placeholder="Tipo (Harina)" onChange={e => setNuevoProd({...nuevoProd, tipo: e.target.value})} required />
              <input style={inputS} placeholder="Marca (Blancaflor)" onChange={e => setNuevoProd({...nuevoProd, marca: e.target.value})} required />
              <input style={inputS} placeholder="Contenido (1kg)" onChange={e => setNuevoProd({...nuevoProd, contenido: e.target.value})} required />
              <input style={inputS} type="number" placeholder="Precio" onChange={e => setNuevoProd({...nuevoProd, precioNuevo: e.target.value})} required />
              <button type="submit" style={btnSave}>Guardar</button>
              <button type="button" onClick={() => setShowManual(false)} style={btnCancel}>Cerrar</button>
            </form>
          </div>
        </div>
      )}

      {/* LISTA DE PRODUCTOS */}
      <div style={listStyle}>
        {loading ? <Loader2 className="animate-spin" /> : ofertas.map(o => (
          <div key={o._id} style={itemStyle}>
            <div style={{flex:1}}>
              <h4 style={{margin:0}}>{o.producto}</h4>
              <p style={{color:'#16a34a', fontWeight:'bold'}}>${o.precioNuevo}</p>
            </div>
            <button style={btnIconDelete} onClick={async () => {
              if(window.confirm("¿Borrar?")) {
                await axios.delete(`${API_URL}/api/ofertas/${o._id}`);
                cargarOfertas();
              }
            }}><Trash2 size={16}/></button>
          </div>
        ))}
      </div>
    </div>
  );
};

// Estilos rápidos para Gestión
const containerStyle = { padding: '40px', maxWidth: '800px', margin: '0 auto' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const btnPlus = { background: '#e67e22', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '10px', marginTop:'20px' };
const itemStyle = { display: 'flex', padding: '15px', background: 'white', borderRadius: '12px', border: '1px solid #f1f5f9', alignItems: 'center' };
const btnIconDelete = { background: '#fef2f2', border: 'none', padding: '10px', borderRadius: '8px', color: '#ef4444', cursor: 'pointer' };
const modalOverlay = { position: 'fixed', top:0, left:0, width:'100%', height:'100%', background:'rgba(0,0,0,0.5)', display:'flex', justifyContent:'center', alignItems:'center' };
const modalContent = { background:'white', padding:'30px', borderRadius:'20px', width:'400px' };
const gridForm = { display:'flex', flexDirection:'column', gap:'10px' };
const inputS = { padding:'10px', borderRadius:'8px', border:'1px solid #ddd' };
const btnSave = { background:'#1e293b', color:'white', padding:'10px', border:'none', borderRadius:'8px', cursor:'pointer' };
const btnCancel = { background:'#f1f5f9', color:'#64748b', padding:'10px', border:'none', borderRadius:'8px', cursor:'pointer' };
const btnBack = { background:'none', border:'none', cursor:'pointer', display:'flex', alignItems:'center', gap:'8px', marginBottom:'20px' };

export default GestionOfertas;
